```class Solution {
public:
    int nextBeautifulNumber(int n) {
        n++;
        while (true) {
            string str = to_string(n);
            unordered_map<char, int> count;
            for (char c : str) {
                count[c]++;
            }
            bool balanced = true;
            for (char c : str) {
                if (count[c] != (c - '0')) {
                    balanced = false;
                    break;
                }
            }
            if (balanced) {
                return n;
            }
            n++;
        }
    }
};
